// Space: O(n * l + 2^n)

// dp, sort, heap, binary search, submask enumeration
class Solution {
public:
    long long minMergeCost(vector<vector<int>>& lists) {
        static const int64_t INF = numeric_limits<int64_t>::max();

        const auto& merge = [](const auto& lists) {
            using T = tuple<int, int, int>;
            vector<T> data;
            data.reserve(size(lists));
            for (int i = 0; i < size(lists); ++i) {
                data.emplace_back(lists[i][0], i, 0);
            }
            priority_queue<T, vector<T>, greater<T>> min_heap(cbegin(data), cend(data));
            vector<int> result;
            while (!empty(min_heap)) {
                const auto [x, i, j] = min_heap.top(); min_heap.pop();
                result.emplace_back(x);
                if (j + 1 < size(lists[i])) {
                    min_heap.emplace(lists[i][j + 1], i, j + 1);
                }
            }
            return result;
        };

        const auto& binary_search = [](int left, int right, const auto& check) {
            while (left <= right) {
                const auto& mid = left + (right - left) / 2;
                if (check(mid)) {
                    right = mid - 1;
                } else {
                    left = mid + 1;
                }
            }
            return left;
        }; 

        vector<int> dp1(1 << size(lists));
        for (int i = 0; i < size(lists); ++i) {  // Time: O(2^n)
            dp1[1 << i] = size(lists[i]);
        }
        for (int mask = 1; mask < size(dp1); ++mask) {  // Time: O(2^n)
            dp1[mask] = dp1[mask ^ (mask & -mask)] + dp1[mask & -mask];
        }
        auto sorted_vals = merge(lists);  // Time: O((n * l) * logn)
        sorted_vals.erase(unique(begin(sorted_vals), end(sorted_vals)), end(sorted_vals));
        vector<int> dp2(1 << size(lists));
        for (int mask = 1; mask < size(dp2); ++mask) {  // Time: O(2^n * log(n * l) * n * logl)
            const auto& check = [&](int x) {
                int cnt = 0;
                for (int i = 0; i < size(lists); ++i) {
                    if ((mask & (1 << i)) == 0) {
                        continue;
                    }
                    cnt += distance(cbegin(lists[i]), upper_bound(cbegin(lists[i]), cend(lists[i]), sorted_vals[x]));
                }
                return cnt >= (dp1[mask] + 1) / 2;
            };

            dp2[mask] = sorted_vals[binary_search(0, size(sorted_vals) - 1, check)];
        }
        vector<int64_t> dp3(1 << size(lists));
        for (int mask = 1; mask < size(dp3); ++mask) {  // Time: O(3^n)
            if ((mask & (mask - 1)) == 0) {
                continue;
            }
            dp3[mask] = INF;
            for (int submask = (mask - 1) & mask; submask > (mask ^ submask); submask = (submask - 1) & mask) {
                dp3[mask] = min(dp3[mask], dp3[submask] + dp3[mask ^ submask] + abs(dp2[submask] - dp2[mask ^ submask]) + dp1[mask]);
            }
        }
        return dp3.back();
    }
};

# Time:  O(l * nlogn + 2^n * log(n * l) * n * logl + 3^n), n = len(lists), l = max(len(list) for list in lists)
# Space: O(n * l + 2^n)

import heapq
import bisect


# dp, sort, heap, binary search, submask enumeration
class Solution(object):
    def minMergeCost(self, lists):
        """
        :type lists: List[List[int]]
        :rtype: int
        """
        INF = float("inf")
        def merge(lists):
            result = []
            min_heap = [(lists[i][0], i, 0) for i in xrange(len(lists))]
            heapq.heapify(min_heap)
            while min_heap:
                x, i, j = heapq.heappop(min_heap)
                result.append(x)
                if j+1 < len(lists[i]):
                    heapq.heappush(min_heap, (lists[i][j+1], i, j+1))
            return result

        def binary_search(left, right, check):
            while left <= right:
                mid = left+(right-left)//2
                if check(mid):
                    right = mid-1
                else:
                    left = mid+1
            return left

        def check(x):
            return sum(bisect.bisect_right(lists[i], sorted_vals[x]) for i in range(len(lists)) if mask&(1<<i)) >= (dp1[mask]+1)//2

        dp1 = [0]*(1<<len(lists))
        for i in xrange(len(lists)):  # Time: O(2^n)
            dp1[1<<i] = len(lists[i])
        for mask in xrange(1, len(dp1)):  # Time: O(2^n)
            dp1[mask] = dp1[mask^(mask&-mask)]+dp1[mask&-mask]
        sorted_vals = merge(lists)  # Time: O(l * nlogn)
        sorted_vals = [sorted_vals[i] for i in xrange(len(sorted_vals)) if i+1 == len(sorted_vals) or sorted_vals[i+1] != sorted_vals[i]]
        dp2 = [0]*(1<<len(lists))
        for mask in xrange(1, len(dp2)):  # Time: O(2^n * log(n * l) * n * logl)
            dp2[mask] = sorted_vals[binary_search(0, len(sorted_vals)-1, check)]
        dp3 = [0]*(1<<len(lists))
        for mask in xrange(1, len(dp3)):  # Time: O(3^n)
            if mask&(mask-1) == 0:
                continue
            dp3[mask] = INF
            submask = (mask-1)&mask
            while submask > mask^submask:
                dp3[mask] = min(dp3[mask], dp3[submask]+dp3[mask^submask]+abs(dp2[submask]-dp2[mask^submask])+dp1[mask])
                submask = (submask-1)&mask
        return dp3[-1]
